mapper.delete:
DELETE FROM order_idempotency
WHERE user_id = #{userId}
  AND operation = #{operation}
  AND idempotency_key = #{idempotencyKey}
  AND expires_at <= #{now}

mapper.select:
SELECT id
FROM order_idempotency
WHERE expires_at <= #{now}
ORDER BY expires_at ASC, id ASC
LIMIT #{batchSize}

